const m={name:"fs",commands:[{name:"ls",aliases:["dir"],description:"List directory contents",usage:"ls [path]",handler:async(e,a,{fs:r})=>{const t=e[0]||".";try{const n=await r.readdir(t);return(await Promise.all(n.map(async i=>{const c=t==="."?i:`${t}/${i}`;try{const o=await r.stat(c);return{name:i,isDirectory:o.isDirectory}}catch{return{name:i,isDirectory:!1}}}))).map(i=>`  ${(i.isDirectory?"[DIR]":"[FILE]").padEnd(7)} ${i.name}`).join(`
`)}catch(n){return`ls: ${n.message}`}}},{name:"cd",description:"Change current directory",usage:"cd <path>",handler:async(e,a,{fs:r})=>{if(!e[0])return r.cwd;try{const t=await r.cd(e[0]);return a.prompt=`${r.rootName}${t}`,""}catch(t){return`cd: ${t.message}`}}},{name:"pwd",description:"Print working directory",handler:async(e,a,{fs:r})=>r.cwd},{name:"cat",description:"Display file contents",usage:"cat <file>",handler:async(e,a,{fs:r})=>{if(!e[0])return"Usage: cat <file>";try{return await r.readFile(e[0],{encoding:"utf8"})}catch(t){return`cat: ${t.message}`}}},{name:"mkdir",description:"Create a directory",usage:"mkdir <path>",handler:async(e,a,{fs:r})=>{if(!e[0])return"Usage: mkdir <path>";try{return await r.mkdir(e[0],{recursive:!0}),""}catch(t){return`mkdir: ${t.message}`}}},{name:"rm",aliases:["del","delete"],description:"Remove a file or directory",usage:"rm [-r] <path>",handler:async(e,a,{fs:r})=>{const t=e[0]==="-r",n=t?e[1]:e[0];if(!n)return"Usage: rm [-r] <path>";try{return(await r.stat(n)).isDirectory?await r.rmdir(n,{recursive:t}):await r.unlink(n),""}catch(s){return`rm: ${s.message}`}}},{name:"mv",aliases:["rename","move"],description:"Move or rename a file",usage:"mv <source> <dest>",handler:async(e,a,{fs:r})=>{if(e.length<2)return"Usage: mv <source> <dest>";try{return await r.rename(e[0],e[1]),""}catch(t){return`mv: ${t.message}`}}},{name:"touch",description:"Create an empty file",usage:"touch <path>",handler:async(e,a,{fs:r})=>{if(!e[0])return"Usage: touch <path>";try{return await r.writeFile(e[0],""),""}catch(t){return`touch: ${t.message}`}}},{name:"stat",aliases:["info"],description:"Display file or directory information",usage:"stat <path>",handler:async(e,a,{fs:r})=>{if(!e[0])return"Usage: stat <path>";try{const t=await r.stat(e[0]);return[`  Path: ${e[0]}`,`  Type: ${t.isDirectory?"directory":"file"}`,`  Size: ${t.size} bytes`,`  Modified: ${new Date(t.mtimeMs).toISOString()}`].join(`
`)}catch(t){return`stat: ${t.message}`}}}]};export{m as default};
